const QUESTIONS_CCZT_C2 = [
  { id:60301, domain:2, level:1, question:"In NIST SP 800-207, which component makes the actual access decision based on policy?", options:["The policy decision point evaluates inputs and renders the grant or deny access result","The policy enforcement point physically blocks or allows the connection to the resource","The continuous diagnostics system scores device health before any request is evaluated","The identity management system issues credentials that subjects present when connecting"], correct:0, explanation:"The PDP renders the access decision; the PEP only enforces it, while CDM and ID systems are data sources feeding the decision." },
  { id:60302, domain:2, level:1, question:"What two logical sub-components together form the policy decision point in NIST SP 800-207?", options:["The policy enforcement point and the resource gateway located near each protected asset","The trust algorithm and the continuous diagnostics and mitigation data feed of hosts","The policy engine and the policy administrator working together as the decision point","The identity management system and the public key infrastructure certificate authority"], correct:2, explanation:"NIST SP 800-207 splits the PDP into the policy engine (decides) and policy administrator (executes the session)." },
  { id:60303, domain:2, level:1, question:"Which logical component ultimately grants, denies, or revokes access in the 800-207 model?", options:["The policy enforcement point that opens and closes the network path to the resource","The data access policy store that passively holds the rules without making any decision","The policy engine that renders the final decision to grant, deny, or revoke a session","The policy administrator that merely relays commands from the external data sources"], correct:2, explanation:"The policy engine makes the decision using the trust algorithm; the PA executes and the PEP enforces the result." },
  { id:60304, domain:2, level:2, question:"What is the primary role of the policy administrator within the policy decision point?", options:["It computes the trust score that ultimately determines whether the request is approved","It collects telemetry from endpoints to assess the current device security posture","It stores the data access policies that the organization has defined for its resources","It establishes and tears down the communication path between the subject and resource"], correct:3, explanation:"The PA executes the PE's decision by configuring the PEP to open or close a session; it does not itself decide." },
  { id:60305, domain:2, level:2, question:"How does the policy administrator communicate an access decision to the enforcement point?", options:["It signals the PEP to establish or to terminate the session path for the given request","It directly authenticates the subject and validates the credentials that were presented","It recalculates the trust algorithm output again each time a single packet is transmitted","It rewrites the organization's data access policy so it matches the current request made"], correct:0, explanation:"The PA instructs the PEP to allow or close the connection; authentication and policy authoring happen in other components." },
  { id:60306, domain:2, level:1, question:"In NIST SP 800-207, what is the principal function of the policy enforcement point?", options:["It calculates the confidence level that is required to approve a subject's access request","It serves as the authoritative source of identity for every subject in the enterprise here","It enables, monitors, and terminates the connections between a subject and a resource","It defines the organization-wide rules governing which subjects may access which assets"], correct:2, explanation:"The PEP enforces the decision by gating the connection; deciding, identity, and policy authoring are separate roles." },
  { id:60307, domain:2, level:2, question:"Where is the policy enforcement point typically positioned relative to the resource it guards?", options:["At the enterprise internet perimeter where all inbound external traffic first arrives","Embedded inside the policy engine so that decisions and enforcement are co-located","As close as practical to the resource, often as a gateway placed in front of the asset","Inside the identity provider so it can enforce the decision during authentication only"], correct:2, explanation:"The PEP sits near the resource as a gateway, separating it from the broader network for per-resource control." },
  { id:60308, domain:2, level:2, question:"In the 800-207 model, the policy enforcement point can be conceptually divided into which two parts?", options:["A policy engine portion and a policy administrator portion sharing a single process","A control plane portion and a separate identity management portion of the architecture","A threat intelligence portion and a continuous diagnostics portion of the host system","A client-side portion and a resource-side portion that coordinate to form the connection"], correct:3, explanation:"NIST describes the PEP as potentially split into client-side and resource-side components; PE and PA are the PDP halves." },
  { id:60309, domain:2, level:1, question:"What does the trust algorithm in a Zero Trust architecture ultimately produce?", options:["A decision on whether to grant access to a particular resource for a given request","A cryptographic key used to encrypt the session between the subject and the resource","A network route that the traffic should follow from the subject toward the target asset","A static list of devices that are considered permanently trusted within the enterprise"], correct:0, explanation:"The trust algorithm consumes inputs and outputs an access decision; it is not a key, route, or static allowlist." },
  { id:60310, domain:2, level:2, question:"Which of the following is a recognized input to the Zero Trust trust algorithm?", options:["The physical distance between the subject's device and the resource measured in meters","The total number of employees who are currently logged in across the whole enterprise","The requesting subject's identity along with its assigned attributes and privileges held","The vendor brand name that is printed on the chassis of the requesting hardware device"], correct:2, explanation:"Subject identity and attributes feed the trust algorithm; the distractors are not meaningful 800-207 inputs." },
  { id:60311, domain:2, level:2, question:"In a criteria-based trust algorithm, how is an access request evaluated for approval?", options:["By assigning a numeric confidence score that is then compared against a single threshold","By the chronological order in which the requests arrived at the policy engine for review","Against a defined set of qualifications, all of which must be met to grant the access","By randomly sampling a subset of the attributes to reduce the evaluation overhead cost"], correct:2, explanation:"Criteria-based algorithms require meeting fixed qualifications; scoring against a threshold is the contextual variant." },
  { id:60312, domain:2, level:2, question:"How does a score-based (contextual) trust algorithm differ from a criteria-based one?", options:["It requires every single defined attribute to be present before any access is permitted","It ignores subject identity entirely and relies only upon the destination resource type","It evaluates the requests strictly in the order that they reach the enforcement point","It computes a weighted confidence value and grants access only if it clears a threshold"], correct:3, explanation:"Score-based algorithms aggregate inputs into a confidence value versus a threshold; criteria-based demands all qualifications." },
  { id:60313, domain:2, level:3, question:"An organization wants access decisions to weigh recent behavior and risk dynamically. Which trust algorithm variation fits best?", options:["A contextual score-based algorithm that aggregates weighted signals into a confidence value","A pure criteria-based algorithm with a fixed, unchanging list of required subject attributes","A singular algorithm that evaluates each request in complete isolation from any prior history","A perimeter-based algorithm that simply trusts any request originating inside the network"], correct:0, explanation:"Score-based contextual algorithms incorporate dynamic, weighted signals; criteria-based and isolated evaluation ignore that context." },
  { id:60314, domain:2, level:3, question:"NIST distinguishes a 'singular' from a 'contextual' trust algorithm based on which factor?", options:["Whether the algorithm is implemented in dedicated hardware rather than in software code","Whether the algorithm is hosted on premises rather than within a public cloud environment","Whether the algorithm considers the subject's history and behavior across prior requests","Whether the algorithm uses symmetric rather than asymmetric cryptographic session keys"], correct:2, explanation:"Contextual algorithms factor in subject history and behavior; singular ones evaluate each request without that context." },
  { id:60315, domain:2, level:1, question:"In Zero Trust, the control plane is primarily responsible for which of the following?", options:["Carrying the actual application traffic that flows between the subject and the resource","Encrypting payloads while they are at rest within the enterprise data storage systems","Making and managing access decisions and configuring the communication paths used","Physically cabling the network devices together within the data center equipment racks"], correct:2, explanation:"The control plane handles decisions and path setup; the data plane carries the actual application traffic." },
  { id:60316, domain:2, level:2, question:"Which activity occurs on the data plane rather than on the control plane in a ZTA?", options:["The policy engine evaluating the trust algorithm for an incoming subject access request","The policy administrator instructing an enforcement point to open a brand-new session","The negotiation of policy between the administrators and the central decision point","The flow of application traffic between an authorized subject and a target resource"], correct:3, explanation:"Once access is granted, actual traffic flows on the data plane; decisions and path setup occur on the control plane." },
  { id:60317, domain:2, level:2, question:"Why does a Zero Trust architecture separate the control plane from the data plane?", options:["So that access decisions are managed independently of the traffic they authorize","So that all encryption can be removed from the data plane to improve raw throughput","So that the perimeter firewall remains the single point of policy control as before","So that subjects can bypass the policy engine entirely for any low-risk request type"], correct:0, explanation:"Separating planes lets the control plane govern decisions while the data plane carries authorized traffic securely." },
  { id:60318, domain:2, level:1, question:"What does 'per-session' access mean within the Zero Trust tenets?", options:["A subject authenticates a single time and then retains access until they manually log out","Each network segment grants standing access to every device that is connected within it","Trust is evaluated and granted for one session and does not persist for an indefinite time","Access is tied to the physical workstation hardware rather than to the user identity used"], correct:2, explanation:"Per-session access means trust is granted for a single session, not permanently; the others reintroduce standing trust." },
  { id:60319, domain:2, level:2, question:"Per the 800-207 tenets, access to one resource grants what regarding other separate resources?", options:["It grants implicit access to all of the other resources within the same network subnet","It permanently elevates the subject's privilege level across the entire enterprise estate","It allows the subject to bypass authentication for the next several requests that follow","It does not automatically grant access to any other separate enterprise resource at all"], correct:3, explanation:"Each resource is accessed per session with least privilege; access to one does not extend to others." },
  { id:60320, domain:2, level:1, question:"Which of the following is one of the seven tenets of Zero Trust in NIST SP 800-207?", options:["All data sources and computing services are considered resources that must be protected","The enterprise perimeter firewall remains the primary boundary of trust enforcement","Devices sitting on the internal LAN are inherently trusted once they connect physically","Users are authenticated a single time and then trusted for the remainder of the workday"], correct:0, explanation:"Tenet one treats all data sources and computing services as resources; the distractors contradict Zero Trust principles." },
  { id:60321, domain:2, level:1, question:"Which statement reflects the Zero Trust tenet on securing communications?", options:["Communication inside the corporate network is trusted and therefore need not be secured","Only the traffic that crosses the internet perimeter requires encryption and inspection","All communication is secured regardless of network location, whether internal or external","Securing communication is optional for any resource that is hosted in a private data center"], correct:2, explanation:"The tenet requires securing all communication regardless of location; internal traffic is not implicitly trusted." },
  { id:60322, domain:2, level:2, question:"The tenet that access is granted on a per-session basis is best applied by which practice?", options:["Issuing one long-lived token that remains valid until the user next changes a password","Trusting any session that happens to originate from a previously authenticated device","Re-evaluating trust for each new session rather than relying on any previous grant made","Granting broad standing access once a device has passed a single initial posture check"], correct:2, explanation:"Per-session means trust is re-evaluated for each session; long-lived or standing grants violate the tenet." },
  { id:60323, domain:2, level:2, question:"Which Zero Trust tenet emphasizes that access is determined by dynamic policy?", options:["Access is determined solely by the subject's static job title recorded in the directory","Access is determined by the particular time of day at which the request happens to occur","Access is determined by which VLAN the requesting device is presently connected into","Access is determined by policy including observable client identity and asset state data"], correct:3, explanation:"Dynamic policy considers identity plus observable state and environmental attributes, not static or location data alone." },
  { id:60324, domain:2, level:2, question:"Which Zero Trust tenet addresses the ongoing monitoring of asset integrity and posture?", options:["The enterprise monitors and measures the integrity and posture of all of its owned assets","The enterprise trusts assets indefinitely once they pass an initial one-time inventory scan","The enterprise inspects its assets only when an external auditor formally requests a review","The enterprise relies on each asset's own self-report without any external verification step"], correct:0, explanation:"This tenet requires continuous monitoring of asset integrity; one-time or self-reported checks are insufficient." },
  { id:60325, domain:2, level:2, question:"Which tenet covers authentication and authorization being strictly enforced before any access?", options:["Authentication is enforced once at the perimeter and then is assumed for all resources","Authorization is granted broadly and is only ever revoked when an incident gets detected","All resource authentication and authorization are dynamic and strictly enforced before access","Authentication is only required for the resources that are classified as highly sensitive"], correct:2, explanation:"The tenet mandates dynamic, strictly enforced authn and authz before each access; selective enforcement violates it." },
  { id:60326, domain:2, level:2, question:"Which tenet relates to collecting data in order to improve the security posture over time?", options:["The enterprise discards its logs immediately so as to minimize its data storage footprint","The enterprise collects data only from external threat feeds and never from internal assets","The enterprise collects data on assets, infrastructure, and communications to improve posture","The enterprise shares all of the collected data publicly in order to encourage transparency"], correct:2, explanation:"The tenet calls for collecting state data to continuously improve posture; discarding or limiting collection undermines it." },
  { id:60327, domain:2, level:3, question:"A company trusts a laptop for the entire workday after a single morning login. Which tenet does this violate?", options:["The tenet requiring all data sources to be treated as protectable enterprise resources","The tenet requiring the enterprise to secure every communication while it is in transit","The tenet requiring all assets to be inventoried within one central asset database","The tenet requiring access to be granted on a per-session basis with re-evaluation"], correct:3, explanation:"All-day standing trust violates per-session access; the other tenets concern resources, communications, and inventory." },
  { id:60328, domain:2, level:3, question:"An enterprise decides that VLAN membership alone determines resource access. Which tenet is breached?", options:["The tenet that access is determined by dynamic policy and not merely by network location","The tenet that all of the communications must be encrypted while they are still in transit","The tenet that the enterprise must continuously monitor the integrity of all of its assets","The tenet that every computing service is to be treated as a protectable resource itself"], correct:0, explanation:"Relying on VLAN or location violates dynamic-policy determination; the other tenets address encryption, monitoring, resources." },
  { id:60329, domain:2, level:1, question:"Which system provides continuous device posture information to the policy engine?", options:["The public key infrastructure that issues certificates to each enterprise subject device","The data access policy repository that stores the resource authorization rules centrally","The continuous diagnostics and mitigation system that supplies current asset state data","The industry threat intelligence feed that describes newly discovered malware campaigns"], correct:2, explanation:"CDM supplies real-time device and asset posture; PKI, policy stores, and threat feeds are separate inputs." },
  { id:60330, domain:2, level:2, question:"What input does a threat intelligence feed contribute to the policy engine's evaluation?", options:["The cryptographic certificates that are used to verify the identity of each subject device","The historical activity logs that are generated internally by the enterprise's own systems","The catalog of resources and their data classification levels within the whole enterprise","External information about active threats and malware used to inform the access decision"], correct:3, explanation:"Threat intelligence feeds give external threat context; certificates, logs, and resource catalogs are different sources." },
  { id:60331, domain:2, level:2, question:"Which data source supplies behavioral and historical context drawn from enterprise systems?", options:["Activity logs and a SIEM that aggregate system events and user behavior over a long period","The PKI that is responsible for issuing and revoking subject and device certificates routinely","The industry compliance regime that dictates which security controls must be implemented","The physical badge-access system that controls who may enter the corporate building floors"], correct:0, explanation:"Activity logs and SIEM provide behavioral context to the PE; PKI and physical access serve different purposes." },
  { id:60332, domain:2, level:2, question:"What role does the identity management system play as an input to the policy engine?", options:["It enforces the session itself by opening and closing the network path to the resource","It measures the real-time integrity of each and every endpoint device on the network here","It provides the authoritative subject identity, attribute, and role information for decisions","It carries the application traffic itself once a particular session has been authorized"], correct:2, explanation:"ID management supplies identity and attribute data to the PE; enforcement, posture, and traffic are handled elsewhere." },
  { id:60333, domain:2, level:3, question:"The policy engine consults the PKI primarily to obtain which kind of information?", options:["A weighted confidence score that is derived from the subject's most recent behavior","Validation of the certificates used to authenticate subjects, services, and devices alike","The network path that the authorized traffic should take to reach the target resource","A list of newly discovered vulnerabilities that affect the enterprise software estate"], correct:1, explanation:"PKI provides certificate and identity validation; scoring, routing, and vulnerability data come from other sources." },
  { id:60334, domain:2, level:3, question:"Which input feeds the policy engine with the organization's resource authorization rules?", options:["The continuous diagnostics system that reports the current endpoint health metrics often","The threat intelligence service that publishes indicators of active enterprise compromise","The data access policy that defines who is permitted to access which enterprise resources","The SIEM that correlates the raw event logs gathered from across the enterprise estate"], correct:2, explanation:"The data access policy defines authorization rules; CDM, threat intel, and SIEM provide other forms of input." },
  { id:60335, domain:2, level:1, question:"In Zero Trust, how broadly is the term 'resource' defined within NIST SP 800-207?", options:["It refers only to the physical servers that are located inside the enterprise data center","It refers strictly to the documents that are stored in the corporate file repository system","It refers exclusively to the user accounts maintained within the identity directory service","It includes data sources, computing services, devices, and applications worth protecting"], correct:3, explanation:"Zero Trust treats virtually all data sources and computing services as resources, far broader than just servers or files." },
  { id:60336, domain:2, level:1, question:"In the device agent and gateway deployment model, where does the gateway component sit?", options:["In front of the resource, acting as the enforcement point positioned near the target asset","On the public internet edge, fully replacing the traditional enterprise perimeter firewall","Inside the policy engine, co-located directly with the trust algorithm decision logic itself","On a central log server, aggregating the events for the SIEM platform to later analyze them"], correct:0, explanation:"The gateway sits in front of each resource as the resource-side PEP, paired with an agent on the client device." },
  { id:60337, domain:2, level:2, question:"Which deployment model uses a single component to protect a group of resources behind it?", options:["The resource portal model, in which each subject installs a local software agent on a device","The enclave-based model, in which one gateway protects a whole collection of resources together","The device sandboxing model, in which every resource runs inside its own dedicated agent","The perimeter model, in which one firewall protects the entire enterprise network at once"], correct:1, explanation:"In the enclave model a gateway fronts a group of resources; the portal and sandboxing models differ structurally." },
  { id:60338, domain:2, level:2, question:"In the resource portal-based deployment model, what acts as the policy enforcement point?", options:["A lightweight agent that is installed on each managed endpoint device by the enterprise","A sandbox that isolates the individual approved applications on the user's own device","A gateway portal that subjects connect to in order to reach the protected enterprise resources","A certificate authority that issues the short-lived access tokens used for each new session"], correct:2, explanation:"The portal model uses a gateway portal as the PEP; no client agent is required, unlike the agent and gateway model." },
  { id:60339, domain:2, level:2, question:"Which deployment variation isolates approved applications directly on a subject's device?", options:["The enclave model that groups multiple backend resources behind one shared front gateway","The resource portal model that requires no software at all to be present on the client device","The device agent model that places a gateway directly in front of each individual resource","The device application sandboxing model that runs vetted apps within isolated device segments"], correct:3, explanation:"Application sandboxing isolates trusted apps on the device; enclave and portal models operate at the resource side." },
  { id:60340, domain:2, level:3, question:"An organization cannot install agents on contractor devices but must protect web apps. Which model fits best?", options:["The resource portal-based model, since it requires no agent to be installed on the client device","The device agent and gateway model, which fundamentally depends on an installed client agent","The device application sandboxing model, which runs the vetted apps directly on the endpoint","The enclave model that mandates endpoint agents on every device that attempts to connect in"], correct:0, explanation:"The portal model needs no client software, fitting unmanaged devices; agent and sandboxing models require device software." },
  { id:60341, domain:2, level:3, question:"Which deployment model is most appropriate when many legacy resources share a single location?", options:["The device sandboxing model that isolates each application on the endpoint individually","The enclave-based model that groups the legacy resources behind a single shared gateway","The portal model that exposes each individual resource through its own dedicated portal","The agentless perimeter model that simply trusts everything inside the legacy segment"], correct:1, explanation:"Enclave deployment fronts a group of often-legacy resources with one gateway; per-app sandboxing fits a different need." },
  { id:60342, domain:2, level:2, question:"Which is a core assumption underlying a Zero Trust architecture as described by NIST?", options:["Devices that sit on the internal network are implicitly trustworthy by their default state","Threats can only ever originate from outside the enterprise network's defined perimeter","The entire enterprise private network is not to be considered any implicit trust zone at all","Once a subject is authenticated, it can be trusted for all of its future requests that follow"], correct:2, explanation:"ZTA assumes the internal network is not an implicit trust zone; the distractors reflect perimeter assumptions ZTA rejects." },
  { id:60343, domain:2, level:2, question:"NIST notes that not all enterprise resources are necessarily located where?", options:["Within reach of the policy engine, which can only ever see the on-premises systems directly","Behind a PEP, because cloud-hosted resources simply cannot be protected by enforcement","Under continuous monitoring, since any remote asset can never be measured by the enterprise","On enterprise-owned infrastructure, because resources may reside in cloud environments too"], correct:3, explanation:"ZTA assumes resources may not be on enterprise-owned infrastructure such as cloud, yet still require protection." },
  { id:60344, domain:2, level:3, question:"A ZTA assumption is that remote subjects and assets cannot fully trust which of the following?", options:["The local network connection that they are using to reach the enterprise resources from afar","The certificates that are issued by the enterprise's own public key infrastructure authority","The policy engine that renders the actual access decision in response to their given request","The enterprise identity provider that stores all of their account attributes for the directory"], correct:0, explanation:"ZTA assumes the local network connection cannot be fully trusted; the enterprise PE, PKI, and IdP remain trusted elements." },
  { id:60345, domain:2, level:2, question:"Which network requirement directly supports a Zero Trust architecture?", options:["The enterprise must flatten all of its networks into one single large and trusted segment","The enterprise can observe and log its traffic to assess and inform the access decisions made","The enterprise must disable encryption so the PEP is able to inspect each and every packet","The enterprise must grant every device a static and permanently trusted network address"], correct:1, explanation:"ZTA requires visibility and logging of traffic; flattening trust, disabling encryption, or static trust contradict the model." },
  { id:60346, domain:2, level:3, question:"Why must enterprise assets reach the PEP but be unreachable otherwise in a ZTA?", options:["To allow the assets to broadcast their availability widely to the public internet at large","To let any internal device connect directly to them without any policy evaluation step","To ensure that resources are only ever accessed through enforced, policy-mediated paths","To remove the need for the policy engine to evaluate each individual request that arrives"], correct:2, explanation:"Resources should be reachable only via the PEP so all access is policy-mediated; direct access defeats ZTA." },
  { id:60347, domain:2, level:2, question:"Which threat specifically targets the availability of the policy decision point in a ZTA?", options:["A stolen credential that lets an attacker impersonate a legitimate enterprise subject","An adversary that uses a proprietary data format in order to evade interoperability checks","A non-person entity that automates tasks while holding overly broad standing privileges","A denial-of-service attack that prevents the PDP from rendering any access decisions"], correct:3, explanation:"DoS against the PDP or PEP can block all access decisions; the others are distinct ZTA threats, not availability attacks." },
  { id:60348, domain:2, level:2, question:"What ZTA threat arises from the compromise or subversion of the PDP or policy administrator?", options:["An attacker who controls the decision process can grant illegitimate access to resources","An attacker loses all of their visibility into the enterprise network traffic flows at once","An attacker is automatically locked out because the PEP always defaults to a deny posture","An attacker can only read but is never able to modify the enterprise's access policy rules"], correct:0, explanation:"Subverting the PDP or PA lets an attacker manipulate decisions and grant unauthorized access, a high-impact threat." },
  { id:60349, domain:2, level:2, question:"Why are stolen credentials a notable threat even within a Zero Trust architecture?", options:["Credentials are completely irrelevant in a ZTA because only the network location matters","An attacker holding valid credentials may satisfy the policy and obtain authorized access","Zero Trust eliminates credentials entirely, so their theft has no possible impact at all","Stolen credentials only ever affect the data plane and can never touch the control plane"], correct:1, explanation:"Valid stolen credentials can pass policy checks; MFA and behavioral analysis mitigate but do not eliminate the risk." },
  { id:60350, domain:2, level:3, question:"Which ZTA concern relates to having limited insight into encrypted enterprise traffic?", options:["The increased ability of the PEP to read every payload regardless of any encryption used","Reduced network visibility that can hinder the inspection and detection of malicious activity","The complete elimination of any need to perform traffic monitoring of any kind whatsoever","The guaranteed detection of every threat simply because all of the traffic is now encrypted"], correct:1, explanation:"Pervasive encryption reduces deep packet visibility, complicating detection; ZTA must rely on metadata and other signals." },
  { id:60351, domain:2, level:3, question:"What risk does a reliance on proprietary data formats introduce to a ZTA deployment?", options:["Vendor lock-in and interoperability gaps that can weaken the overall security architecture","Guaranteed compatibility among all of the components from any single vendor in the market","Automatic encryption of all of the policy data regardless of which vendor was chosen for it","The elimination of any need to monitor the non-person entities operating in the system at all"], correct:0, explanation:"Proprietary formats cause lock-in and interoperability problems; they do not guarantee compatibility or improve security." },
  { id:60352, domain:2, level:3, question:"Why are non-person entities a distinct threat consideration within a Zero Trust architecture?", options:["Automated agents are inherently incapable of being granted any access rights to resources","Automated agents may hold credentials and act with privileges that an attacker can abuse","Automated agents never require any authentication of any kind within the Zero Trust model","Automated agents always operate exclusively on the isolated data plane and nowhere else"], correct:1, explanation:"NPEs such as service accounts carry privileges that can be abused if compromised, so they require careful governance." },
  { id:60353, domain:2, level:1, question:"The CISA Zero Trust Maturity Model is organized around how many primary pillars?", options:["Five pillars: identity, devices, networks, applications and workloads, and finally data","Three pillars covering only the identity, the network, and the data protection layers","Seven pillars matching exactly the seven tenets defined within NIST SP 800-207 doc","Two pillars representing the control plane and the data plane treated separately here"], correct:0, explanation:"CISA's ZTMM uses five pillars plus cross-cutting capabilities; it is distinct from the seven NIST tenets." },
  { id:60354, domain:2, level:2, question:"In the CISA ZTMM, which items are described as cross-cutting capabilities spanning the pillars?", options:["Identity, credential, and access management used exclusively for the human user accounts","Perimeter firewalls, VPN concentrators, and intrusion prevention sensors at the network edge","Visibility and analytics, automation and orchestration, and governance across the pillars","Hardware security modules, smart cards, and biometric token readers used at the endpoints"], correct:2, explanation:"CISA lists visibility and analytics, automation and orchestration, and governance as cross-cutting capabilities." },
  { id:60355, domain:2, level:2, question:"The CISA Zero Trust Maturity Model defines its maturity stages progressing in which order?", options:["Bronze, then silver, then gold, and finally the platinum maturity tier at the very top","Level one, then level two, and finally level three out of three total maturity stages","Planning, then piloting, then deploying, and finally decommissioning the architecture","Traditional, then initial, then advanced, and finally the optimal stage of maturity reached"], correct:3, explanation:"CISA's stages are Traditional, Initial, Advanced, and Optimal; the other naming schemes are not used by the model." },
  { id:60356, domain:2, level:3, question:"An enterprise has fully automated, dynamic policy across all five CISA pillars. Which stage is this?", options:["The optimal stage, which is characterized by fully automated and dynamic enterprise policy","The initial stage, in which some automation begins but most of the controls remain manual","The traditional stage, which still relies on manual configuration and on static policy rules","The advanced stage, which has partial automation that still requires some manual oversight"], correct:0, explanation:"Full automation and dynamic policy across pillars indicates the Optimal stage; lower stages retain manual elements." },
  { id:60357, domain:2, level:1, question:"The DoD Zero Trust Reference Architecture organizes capabilities around how many pillars?", options:["Five pillars that are identical to the pillars of the CISA Zero Trust Maturity Model","Seven pillars spanning the user, device, network, application, data, and further areas","Three pillars covering only the people, the process, and the technology domains in scope","Two pillars that split the architecture into a control plane and a data plane separately"], correct:1, explanation:"The DoD ZTRA uses seven pillars; it differs from CISA's five-pillar maturity model in structure." },
  { id:60358, domain:2, level:3, question:"Which concept is emphasized strongly by the DoD Zero Trust Reference Architecture?", options:["A reliance on a fortified network perimeter serving as the principal line of the defense","One-time authentication that grants persistent access in order to improve the efficiency","Continuous authentication and authorization tied closely to data-centric protection goals","Trusting all of the assets that reside within the classified network enclaves by default"], correct:2, explanation:"The DoD ZTRA stresses continuous authn and authz and data-centric security; it rejects perimeter-only trust models." },
  { id:60359, domain:2, level:2, question:"What is the relationship between a policy enforcement point and the resource it protects?", options:["The resource bypasses the PEP for any request that comes from an internal network address","The PEP and the resource share credentials so that neither of them needs to authenticate","The resource itself configures the policy engine each time that a new request arrives in","The PEP mediates every connection so the resource is reachable only through that PEP"], correct:3, explanation:"The PEP mediates all access to the resource; bypassing it or sharing credentials would defeat enforcement." },
  { id:60360, domain:2, level:2, question:"After the policy engine approves a request, what happens next in the ZTA workflow?", options:["The policy administrator directs the enforcement point to establish the session connection","The policy engine itself opens the network path directly to the target enterprise resource","The subject connects straight to the resource without any enforcement step taking place","The identity provider re-issues the credentials before any traffic is permitted to flow"], correct:0, explanation:"On approval the PA tells the PEP to set up the session; the PE decides but does not itself open the connection." },
  { id:60361, domain:2, level:3, question:"How does a Zero Trust system end access when a session is deemed risky mid-stream?", options:["The resource silently ignores the further packets without notifying any other component","The policy administrator instructs the enforcement point to terminate the active session","The trust algorithm deletes the subject's identity record from the directory immediately","The control plane begins carrying the data traffic in order to slow down the attacker first"], correct:1, explanation:"Continuous evaluation lets the PA tell the PEP to tear down a risky session; the other options misassign responsibilities." },
  { id:60362, domain:2, level:1, question:"In NIST SP 800-207, the policy engine and policy administrator are conceptually part of what?", options:["The data plane that carries the authorized application traffic between the two endpoints","The policy decision point that is responsible for making and executing access decisions","The policy enforcement point that physically gates the connection to the target resource","The continuous diagnostics system that constantly reports on the current endpoint posture"], correct:1, explanation:"The PE and PA together comprise the PDP; the PEP is a separate enforcement component and CDM is a data source." },
  { id:60363, domain:2, level:2, question:"Which statement best captures the division of labor between the PE and the PA?", options:["The PE physically opens the session and the PA evaluates the trust algorithm thoroughly","The PE and the PA both authenticate the subject before any access decision can be reached","The PE makes the access decision and the PA carries that decision out by configuring access","The PE stores the access policy and the PA stores the subject identity records carefully"], correct:2, explanation:"The PE decides using policy and the PA executes the decision; neither authenticates nor stores identity directly." },
  { id:60364, domain:2, level:2, question:"A subject's device fails a health check during an active session. What should a ZTA do?", options:["Continue the session unchanged because the device was already trusted at login time","Re-evaluate the access and potentially terminate the session based on the new posture data","Permanently delete the device from the enterprise inventory and block its certificate","Ignore the change since posture only matters at the initial authentication moment alone"], correct:1, explanation:"ZTA continuously evaluates posture and can revoke access mid-session; trust is not static after login." },
  { id:60365, domain:2, level:3, question:"In a ZTA, why is reducing the implicit trust zone around a resource considered desirable?", options:["It removes the requirement for the policy engine to evaluate any of the incoming requests","It shrinks the area where access is granted without explicit per-request policy evaluation","It allows every internal device to reach the resource freely without any enforcement step","It eliminates the need to encrypt the communications that travel toward the resource itself"], correct:1, explanation:"Shrinking the implicit trust zone forces explicit per-request evaluation, reducing the blast radius of a compromise." },
  { id:60366, domain:2, level:1, question:"What is the core purpose of a policy enforcement point in plain terms?", options:["To decide, using the trust algorithm, whether any given access request should be approved","To act as the authoritative directory storing all of the subject identities and attributes","To turn the access decision into an actual allowed or blocked connection at the resource","To generate the threat intelligence used to inform the policy engine's later decisions"], correct:2, explanation:"The PEP turns a decision into an enforced connection; deciding, identity, and threat intel are other functions." },
  { id:60367, domain:2, level:2, question:"Which best describes the trust algorithm's relationship to the policy engine?", options:["The trust algorithm is the logic the policy engine uses to compute its access decisions","The trust algorithm is a separate hardware device that sits in front of every resource","The trust algorithm is the data plane mechanism that carries the authorized traffic onward","The trust algorithm is the credential store that the identity provider queries on each login"], correct:0, explanation:"The trust algorithm is the decision logic within the PE; it is not hardware, a data plane, or a credential store." },
  { id:60368, domain:2, level:2, question:"Which factor would a contextual trust algorithm most likely incorporate?", options:["Only the static role of the subject as it is recorded in the human resources database","The subject's recent access patterns and any deviations from the established baseline","Solely the brand of network switch through which the request happens to be flowing","Exclusively the time zone configured on the resource server's internal system clock"], correct:1, explanation:"Contextual algorithms weigh behavioral history and anomalies; static role alone reflects a simpler criteria approach." },
  { id:60369, domain:2, level:3, question:"A ZTA design routes all decision traffic separately from application traffic. This reflects what principle?", options:["The collapse of the control and data planes into one shared channel for simplicity reasons","The separation of the control plane from the data plane within the architecture overall","The elimination of the policy enforcement point in favor of perimeter-based control instead","The reliance on implicit network trust for all of the traffic that stays inside the network"], correct:1, explanation:"Keeping decision traffic separate from application traffic reflects control-plane and data-plane separation." },
  { id:60370, domain:2, level:1, question:"Which of these is correctly identified as a data source for the policy engine?", options:["The policy enforcement point that gates the actual connection to the protected resource","A security information and event management system aggregating logs for the decision input","The data plane channel that carries the authorized traffic between subject and resource","The session token that is presented by the subject when it connects to a given resource"], correct:1, explanation:"A SIEM is a recognized data source feeding the PE; the PEP, data plane, and tokens are not PE input sources." },
  { id:60371, domain:2, level:2, question:"Why does NIST recommend collecting continuous diagnostics data in a ZTA?", options:["So that posture decisions can be removed entirely from the trust algorithm computation","So the policy engine can incorporate current asset state when deciding on each request","So that the enterprise can permanently trust any asset that passes a single initial scan","So the data plane is able to carry the diagnostics traffic instead of application traffic"], correct:1, explanation:"CDM data lets the PE factor real-time asset state into decisions; ZTA avoids permanent trust from one scan." },
  { id:60372, domain:2, level:2, question:"Which scenario best illustrates the per-session access tenet in practice?", options:["A user is granted standing access to a database for as long as their account stays active","A user must satisfy policy each time they open a new connection to a protected resource","A user authenticates once in the morning and retains all access until the next morning","A device on the trusted subnet gains automatic access to all servers within that subnet"], correct:1, explanation:"Per-session access requires policy satisfaction for each new connection; standing or location-based trust violates it." },
  { id:60373, domain:2, level:3, question:"An attacker performs a sustained DoS against the policy administrator. What is the likely effect?", options:["Application traffic continues flowing because the data plane operates independently always","New sessions cannot be established because decisions cannot be executed onto the PEP","All previously denied subjects are automatically granted access during the disruption","The trust algorithm switches to a criteria-based mode to maintain full availability now"], correct:1, explanation:"A DoS on the PA prevents decision execution, blocking new session setup; it does not auto-grant denied access." },
  { id:60374, domain:2, level:1, question:"Which statement about the enforcement point's location is most accurate in a ZTA?", options:["It is always placed at the single internet-facing perimeter of the whole enterprise network","It is distributed and placed close to resources so each access path can be controlled locally","It is embedded only inside the identity provider so it can act during the login event only","It is located on the public cloud control plane and never on the enterprise premises at all"], correct:1, explanation:"PEPs are distributed near resources for granular control; a single perimeter PEP reflects the old model ZTA replaces." },
  { id:60375, domain:2, level:2, question:"What distinguishes the resource portal model from the device agent and gateway model?", options:["The portal model requires a heavyweight agent on every endpoint, unlike the gateway model","The portal model needs no software on the client device, unlike the agent-based approach used","The portal model removes the policy engine entirely from the decision-making process here","The portal model trusts all internal devices implicitly without any policy evaluation step"], correct:1, explanation:"The portal model is agentless on the client side; the device agent model requires installed client software." },
  { id:60376, domain:2, level:2, question:"In the enclave-based deployment, what is a notable limitation compared to per-resource gateways?", options:["It cannot enforce any access policy at all on the resources placed within the enclave zone","The gateway grants access at the enclave level, offering coarser control than per resource","It requires installing a separate agent on every single backend resource within the enclave","It removes the need for a policy decision point because the enclave is inherently trusted"], correct:1, explanation:"Enclave gateways protect a group, giving coarser granularity than a dedicated PEP per individual resource." },
  { id:60377, domain:2, level:3, question:"Why might device application sandboxing be chosen over a full device agent approach?", options:["It allows trusted apps to be isolated even when the rest of the device is not fully trusted","It removes the requirement for any policy decision point to evaluate the access requests","It guarantees that all of the resources are reachable directly without any enforcement","It eliminates the need to authenticate the subject before granting access to the resources"], correct:0, explanation:"Sandboxing isolates vetted apps from an untrusted device; it still relies on a PDP, PEP, and authentication." },
  { id:60378, domain:2, level:1, question:"Which of the following correctly pairs a ZTA component with its function?", options:["Policy engine: physically opening and closing the network connection to the resource itself","Policy enforcement point: enabling, monitoring, and terminating the connection to a resource","Policy administrator: computing the trust score that decides whether to approve a request","Identity provider: carrying the authorized application traffic across the network data plane"], correct:1, explanation:"The PEP enables, monitors, and ends connections; the PE decides, the PA executes, and the IdP supplies identity." },
  { id:60379, domain:2, level:2, question:"What does NIST mean when it says trust is never granted implicitly in a ZTA?", options:["Access is granted automatically to any device that is physically inside the office building","No subject or asset is trusted by default merely due to its location or its network position","Every subject is trusted once it has authenticated for the very first time in a given day","Internal traffic is exempt from policy because it never leaves the enterprise boundary at all"], correct:1, explanation:"Implicit trust based on location or one-time authentication is rejected; every request is evaluated against policy." },
  { id:60380, domain:2, level:2, question:"Which describes a valid input combination the trust algorithm may consider?", options:["Subject identity, device posture, resource sensitivity, and current threat intelligence data","Only the subject's username and nothing else about the device, resource, or environment","Solely the destination IP address of the resource the subject is attempting to reach now","Exclusively the cable type connecting the subject's device to the local network switch port"], correct:0, explanation:"The trust algorithm weighs many inputs such as identity, posture, sensitivity, and threat intel together for a decision." },
  { id:60381, domain:2, level:3, question:"A criteria-based trust algorithm is configured so that one missing attribute blocks access. Why?", options:["Because criteria-based algorithms require all qualifications to be present before granting access","Because criteria-based algorithms randomly select which attributes actually matter each time","Because criteria-based algorithms always grant access regardless of any missing attributes","Because criteria-based algorithms compute a partial score and allow access above a threshold"], correct:0, explanation:"Criteria-based algorithms demand every qualification be met; partial scoring is the contextual approach instead." },
  { id:60382, domain:2, level:1, question:"Which plane does the actual subject-to-resource application traffic travel on in a ZTA?", options:["The control plane, which is responsible for making and managing the access decisions","The data plane, which carries the authorized application traffic after access is granted","The management plane, which exists only to monitor the health of the network devices","The identity plane, which exclusively handles the issuance of the subject credentials"], correct:1, explanation:"Authorized application traffic flows on the data plane; the control plane handles decisions and path management." },
  { id:60383, domain:2, level:2, question:"How should an enterprise treat communications between two internal microservices in a ZTA?", options:["As inherently trusted traffic that requires no authentication because it is internal only","As traffic that still must be authenticated, authorized, and secured like any other request","As traffic exempt from logging because it never crosses the enterprise network perimeter","As traffic that the policy engine should ignore to reduce the decision processing overhead"], correct:1, explanation:"ZTA treats internal service-to-service traffic with the same scrutiny as any other; internal does not mean trusted." },
  { id:60384, domain:2, level:2, question:"Which is an accurate statement about the seven tenets as a whole?", options:["They apply only to remote users and not to the assets located on the enterprise premises","They collectively describe how to grant and continuously evaluate access without implicit trust","They are an optional set of recommendations that can be skipped in any cloud deployment","They replace the need for any policy decision point by defining static access rules upfront"], correct:1, explanation:"The seven tenets collectively guide access granting and continuous evaluation without implicit trust." },
  { id:60385, domain:2, level:3, question:"An enterprise wants to detect lateral movement after an initial compromise. Which ZTA property helps most?", options:["Per-resource enforcement so that access to one resource does not extend to other resources","A flat trusted network that lets internal hosts communicate freely without any restriction","One-time authentication at login that avoids re-checking the subject during the session","Implicit trust for any device that sits within the same subnet as the compromised host"], correct:0, explanation:"Per-resource enforcement and least privilege limit lateral movement; flat networks and implicit trust enable it." },
  { id:60386, domain:2, level:1, question:"What is the primary purpose of feeding SIEM data into the policy engine?", options:["To replace the policy enforcement point with a centralized logging-driven control mechanism","To provide aggregated event and behavioral context that informs the access decisions made","To carry the authorized application traffic on behalf of the resource being protected here","To issue the cryptographic certificates that subjects present during their authentication"], correct:1, explanation:"SIEM provides aggregated behavioral context to inform PE decisions; it does not enforce, carry traffic, or issue certs." },
  { id:60387, domain:2, level:2, question:"Why is the policy enforcement point sometimes split into client and resource components?", options:["So that the policy engine no longer needs to evaluate any of the access requests received","So that enforcement can occur at both the requesting side and the resource side of a connection","So that the data plane and the control plane can be merged into one combined channel here","So that the subject can authenticate directly to the resource without any decision step at all"], correct:1, explanation:"Splitting the PEP allows enforcement at both ends of the connection; it does not remove the PE or merge planes." },
  { id:60388, domain:2, level:2, question:"Which assumption about visibility does a ZTA make regarding enterprise communication?", options:["That all communication is plaintext and therefore can be inspected fully without any effort","That the enterprise can collect metadata and logs even when payloads are encrypted in transit","That no monitoring is required because encryption alone guarantees the security of the traffic","That only the perimeter firewall needs visibility into the traffic crossing the boundary here"], correct:1, explanation:"ZTA assumes the enterprise gathers metadata and logs despite encryption; it does not assume plaintext or skip monitoring." },
  { id:60389, domain:2, level:3, question:"A ZTA relies on a single vendor's closed format for all policy data. What threat does this raise?", options:["Improved security because closed formats are inherently impossible for attackers to read","Interoperability and lock-in risk that can hinder integration and resilience across the system","Automatic compliance with every regulatory framework that the enterprise must satisfy fully","Guaranteed availability of the policy engine even during a denial-of-service attack event"], correct:1, explanation:"Proprietary formats create lock-in and interoperability risk; they do not improve security or guarantee compliance." },
  { id:60390, domain:2, level:1, question:"In the CISA maturity model, which is one of the five core pillars?", options:["Perimeter, which represents the hardened network boundary defended by the firewall layer","Devices, which represents the security posture and integrity of the connecting endpoints","Encryption, which represents the cryptographic protection applied to all the stored data","Governance, which is actually a cross-cutting capability rather than a core named pillar"], correct:1, explanation:"Devices is one of the five CISA pillars; perimeter is not a pillar, and governance is a cross-cutting capability." },
  { id:60391, domain:2, level:2, question:"How does the CISA maturity model help an organization adopting Zero Trust?", options:["It provides a single mandatory product that organizations must purchase to be compliant","It offers a staged framework to assess and advance maturity across each of the five pillars","It eliminates the need for any policy decision point by defining fixed network boundaries","It guarantees full Zero Trust the moment an organization reaches the very first stage listed"], correct:1, explanation:"The model offers staged maturity guidance across pillars; it is not a product and maturity is progressive, not instant." },
  { id:60392, domain:2, level:3, question:"How does the DoD Zero Trust Reference Architecture conceptually relate to NIST SP 800-207?", options:["It directly contradicts NIST by reintroducing perimeter-only trust as the primary approach","It builds on Zero Trust principles, organizing capabilities into pillars for defense adoption","It replaces NIST entirely and forbids using any of the NIST logical component definitions","It applies only to physical security controls and ignores network and identity controls fully"], correct:1, explanation:"The DoD ZTRA operationalizes Zero Trust principles into pillars for defense use; it aligns with rather than contradicts NIST." },
  { id:60393, domain:2, level:1, question:"Which best defines a 'subject' in NIST SP 800-207 terminology?", options:["The user, application, or non-person entity that is requesting access to a given resource","The gateway device that always sits directly in front of every protected enterprise resource","The trust algorithm logic that computes whether the access request should be approved here","The data access policy repository that stores the authorization rules for the enterprise estate"], correct:0, explanation:"A subject is the requesting entity (human or NPE); the others are the PEP, the decision logic, and a data source." },
  { id:60394, domain:2, level:2, question:"What is the consequence of a compromised PEP in a Zero Trust architecture?", options:["The trust algorithm automatically reverts to a criteria-based mode to compensate fully here","All access decisions are immediately and permanently delegated to the identity provider now","An attacker may be able to bypass enforcement and reach the resource the PEP protected","The control plane begins carrying the application traffic to maintain service availability"], correct:2, explanation:"A compromised PEP can let an attacker bypass enforcement to reach the resource; it is a critical component to protect." },
  { id:60395, domain:2, level:2, question:"Which best explains why ZTA requires strong identity management as a foundation?", options:["Because identity is the only attribute that the trust algorithm is ever permitted to use","Because identity management physically enforces the connection to the protected resource","Because access decisions depend heavily on accurate subject identity and attribute data","Because identity management removes the requirement for any continuous device monitoring"], correct:2, explanation:"Accurate identity and attribute data underpin access decisions; ID management informs but does not enforce connections." },
  { id:60396, domain:2, level:3, question:"An organization grants a service account broad standing privileges that are never reviewed. Which ZTA threat is this?", options:["A denial-of-service threat that targets the availability of the policy decision point directly","A proprietary data format threat that creates vendor lock-in across the policy components here","The non-person entity threat, where automated agents accumulate excessive, abusable privileges","A visibility threat caused by encrypted traffic that hides the malicious activity from sensors"], correct:2, explanation:"Unreviewed broad NPE privileges exemplify the non-person entity threat; the others describe distinct ZTA risks." },
  { id:60397, domain:2, level:1, question:"Which phrase best summarizes the relationship of the PEP to the protected resource?", options:["The PEP is the gatekeeper through which all access to the resource must necessarily pass","The PEP is the central directory that stores the resource's owner and classification metadata","The PEP is the decision logic that computes whether the resource request will be approved","The PEP is the threat feed that warns the resource about newly discovered malware threats"], correct:0, explanation:"The PEP is the gatekeeper mediating all access to the resource; deciding, directory, and threat feed are other roles." },
  { id:60398, domain:2, level:2, question:"During session establishment, what is the correct ordering of component actions?", options:["The PEP decides, then the PA enforces, and finally the PE logs the completed connection","The PE decides, then the PA executes, and finally the PEP establishes the actual session","The PA decides, then the PE enforces, and finally the identity provider logs the session","The resource decides, then the PEP authenticates, and finally the PE opens the connection"], correct:1, explanation:"The PE decides, the PA executes that decision, and the PEP establishes the session; the other orderings are incorrect." },
  { id:60399, domain:2, level:3, question:"Why must a ZTA continuously monitor sessions rather than only at the point of initial access?", options:["Because the trust algorithm can only ever evaluate a request a single time at connection start","Because conditions and risk can change mid-session, requiring re-evaluation and possible revocation","Because continuous monitoring removes the need for any policy enforcement point in the design","Because the data plane requires constant decisions to be able to carry the application traffic"], correct:1, explanation:"Risk can change mid-session, so ZTA re-evaluates and may revoke access; trust is dynamic rather than one-time only." },
  { id:60400, domain:2, level:1, question:"Which of the following is NOT one of the core NIST SP 800-207 logical components?", options:["The policy engine that makes the actual access decision using the configured trust algorithm","The policy administrator that executes the decision and configures the enforcement point itself","The perimeter firewall that serves as the single trust boundary for the whole enterprise edge","The policy enforcement point that gates the connection between the subject and the resource"], correct:2, explanation:"The PE, PA, and PEP are core 800-207 components; a single perimeter firewall as the trust boundary is what ZTA replaces." },
  { id:60401, domain:2, level:2, question:"What is the role of the data access policy within the policy engine's operation?", options:["It physically opens the connection to the resource once the access has been approved fully","It defines the rules and attributes the policy engine applies when evaluating each request","It carries the authorized application traffic between the subject and the protected resource","It issues and revokes the certificates used to authenticate the subjects and their devices"], correct:1, explanation:"The data access policy supplies the rules the PE applies; it does not open connections, carry traffic, or issue certs." },
  { id:60402, domain:2, level:2, question:"Which best describes how a ZTA handles a request from an unmanaged personal device?", options:["It automatically trusts the device because the authenticated user is a known employee here","It evaluates the device posture and identity against policy before deciding on the access","It grants full access since the user already passed perimeter authentication earlier today","It blocks all access outright because only fully managed devices may ever connect at all"], correct:1, explanation:"ZTA evaluates posture and identity against policy regardless of device ownership; it neither auto-trusts nor blanket-blocks." },
  { id:60403, domain:2, level:3, question:"A trust algorithm input from CDM indicates a device is missing a critical patch. What is a likely ZTA outcome?", options:["The device is granted full access because identity authentication already succeeded earlier","The policy engine may deny or restrict access based on the elevated risk that posture shows","The device is permanently removed from the directory and its certificate is revoked at once","The trust algorithm ignores posture entirely and decides using subject identity by itself"], correct:1, explanation:"Poor posture from CDM raises risk, so the PE may deny or restrict access; posture is a key trust algorithm input." },
  { id:60404, domain:2, level:1, question:"What does the abbreviation PDP stand for in NIST SP 800-207?", options:["Policy distribution protocol, the standard used to publish rules to the network devices","Policy decision point, the logical component that makes and manages the access decisions","Protected data perimeter, the boundary that surrounds the most sensitive enterprise data","Primary device profile, the baseline configuration applied to every managed endpoint device"], correct:1, explanation:"PDP is the policy decision point comprising the PE and PA; the other expansions are not 800-207 terms." },
  { id:60405, domain:2, level:1, question:"What does the abbreviation PEP stand for in NIST SP 800-207?", options:["Policy enforcement point, the component enabling and terminating the connection to a resource","Protected enterprise perimeter, the hardened boundary that surrounds the corporate network edge","Primary encryption protocol, the cipher suite used to secure all of the in-transit traffic now","Privileged escalation path, the route an administrator uses to gain elevated access rights here"], correct:0, explanation:"PEP is the policy enforcement point that gates connections; the other expansions are not 800-207 terminology." },
  { id:60406, domain:2, level:2, question:"Which is true about how policy is administered in a NIST SP 800-207 ZTA?", options:["Policy is hard-coded into each resource and cannot be changed without replacing the resource","Policy is centrally defined and the policy engine applies it dynamically to each access request","Policy is determined solely by which physical port a device is plugged into on the switch","Policy is set by each individual user for the resources that the user personally owns alone"], correct:1, explanation:"Policy is centrally defined and applied dynamically per request by the PE; it is not hard-coded or port-based." },
  { id:60407, domain:2, level:3, question:"Why is denial of service against the PDP considered an especially serious ZTA threat?", options:["Because the data plane immediately stops carrying any traffic the instant the PDP goes down","Because the trust algorithm silently grants access to every requester during the outage period","Because all previously authenticated sessions are automatically and permanently terminated","Because no new access decisions can be made, effectively halting legitimate access enterprise-wide"], correct:3, explanation:"If the PDP cannot decide, no new access is granted, which can halt legitimate access; it does not auto-grant or kill all sessions." },
  { id:60408, domain:2, level:1, question:"Which describes the correct flow when a subject requests access in a ZTA?", options:["The subject's request is evaluated by the PDP, and the PEP enforces the resulting decision","The subject connects to the resource directly, and logging occurs only after the session ends","The PEP makes the access decision, and the PDP simply opens the network path to the resource","The identity provider grants access and then notifies the resource that the subject may connect"], correct:0, explanation:"The PDP evaluates and decides, then the PEP enforces; the PEP does not decide and the IdP does not grant resource access." },
  { id:60409, domain:2, level:2, question:"Which statement about ZTA network requirements is accurate?", options:["The enterprise network must be entirely flat with no segmentation to simplify the routing","Enterprise systems should not be reachable except through the enforcement point that guards them","All encryption must be disabled so the enforcement point can inspect every byte of the traffic","Every device must be assigned a permanent static trust level based on its hardware vendor here"], correct:1, explanation:"Resources should be reachable only via the PEP; flat networks, disabling encryption, and static vendor trust contradict ZTA." },
  { id:60410, domain:2, level:2, question:"How does a ZTA reduce the impact of stolen credentials compared to a perimeter model?", options:["It makes credentials entirely unnecessary, so theft of them has no impact on the system at all","It trusts any request bearing valid credentials regardless of the device or behavior involved here","It stores all credentials in plaintext so administrators can quickly detect any unauthorized use","It adds continuous, contextual evaluation so anomalies can trigger denial despite valid credentials"], correct:3, explanation:"Continuous contextual evaluation can flag anomalies even with valid credentials; ZTA does not remove credentials or trust blindly." },
  { id:60411, domain:2, level:3, question:"An organization wants the trust algorithm to deny access if confidence falls below a set value. Which type is this?", options:["A criteria-based algorithm that requires every defined attribute to be individually present","A perimeter-based algorithm that trusts requests originating from inside the network zone","A singular algorithm that completely ignores the subject's history and prior behavior data","A score-based algorithm that compares an aggregated confidence value against a threshold"], correct:3, explanation:"Comparing an aggregated confidence value to a threshold is the score-based approach; criteria-based demands all attributes." },
  { id:60412, domain:2, level:1, question:"What is the function of the policy engine's connection to the trust algorithm?", options:["The policy engine uses the trust algorithm as the logic that produces each access decision","The policy engine forwards all traffic through the trust algorithm before it reaches a resource","The policy engine relies on the trust algorithm only to store the subject identity attributes","The policy engine uses the trust algorithm purely to encrypt the data sent to the resource"], correct:0, explanation:"The trust algorithm is the decision logic the PE invokes; it does not route traffic, store identity, or encrypt data." },
  { id:60413, domain:2, level:2, question:"Which best captures the meaning of 'assume breach' as applied within a ZTA?", options:["Operators design as if attackers are already present and work to limit the blast radius","Operators assume the perimeter firewall will always succeed in stopping external attackers","Operators assume that internal users are inherently trustworthy and present very low risk","Operators assume encryption by itself is sufficient to prevent any possible data exfiltration"], correct:0, explanation:"Assume breach means designing as if adversaries are inside and minimizing blast radius; it rejects reliance on the perimeter." },
  { id:60414, domain:2, level:2, question:"In a ZTA, why is the resource generally not directly reachable on the network?", options:["Because direct reachability would let the resource bypass the identity provider during login","Because the data plane cannot function unless the resource is hidden from all of the subjects","Because resources are required to remain offline until an administrator manually enables them","Because access must be mediated by the enforcement point so policy is applied to every request"], correct:3, explanation:"Hiding the resource behind the PEP ensures every request is policy-mediated; it is not about offline status or the data plane." },
  { id:60415, domain:2, level:3, question:"A ZTA design must support both managed laptops and unmanaged contractor tablets accessing web apps. What combination fits?", options:["Device agent and gateway for everything, forcing contractors to install the corporate agent","Perimeter VPN access for all devices, after which no further policy evaluation is performed","A single flat trusted network granting both device types unrestricted internal access alike","Agent and gateway for managed laptops, plus a resource portal for the unmanaged tablets used"], correct:3, explanation:"Agent and gateway suits managed devices while the agentless portal suits unmanaged ones; flat or VPN-only models break ZTA." },
  { id:60416, domain:2, level:1, question:"Which of the following accurately describes the policy administrator's outputs?", options:["It produces threat intelligence reports that are consumed by the policy engine during decisions","It produces the cryptographic certificates that authenticate the subjects and their endpoints","It produces commands that configure the enforcement point to open or close subject sessions","It produces the application traffic that flows across the data plane to the protected resource"], correct:2, explanation:"The PA issues commands to configure the PEP for session setup or teardown; it does not produce threat intel, certs, or traffic." },
  { id:60417, domain:2, level:2, question:"Which is a correct statement about combining multiple ZTA deployment models?", options:["Deployment models are mutually exclusive and an enterprise may only ever select one of them","Combining models is forbidden because it would require disabling the policy decision point","An enterprise may combine models, such as agents for some assets and a portal for others","Combining models removes the need for any enforcement point across the entire architecture"], correct:2, explanation:"Enterprises commonly mix deployment models to fit different use cases; the models are not mutually exclusive." },
  { id:60418, domain:2, level:2, question:"What is a key reason ZTA emphasizes logging and analytics of network activity?", options:["To eliminate the need for any policy enforcement point by relying solely on the log records","To permanently trust any device whose activity has been logged at least once previously here","To provide visibility that informs trust decisions and supports the detection of anomalies","To allow the control plane to carry application traffic when the data plane is unavailable now"], correct:2, explanation:"Logging and analytics provide visibility for trust decisions and anomaly detection; they do not replace the PEP or grant trust." },
  { id:60419, domain:2, level:3, question:"An enterprise notices its ZTA cannot inspect encrypted east-west traffic. Which compensating approach aligns with ZTA?", options:["Disable encryption for all internal traffic so deep packet inspection becomes possible again","Rely on identity, posture, and metadata signals to inform decisions despite limited payload view","Trust all encrypted internal traffic implicitly since encryption already guarantees its safety","Remove the enforcement points for east-west traffic to reduce the inspection overhead entirely"], correct:1, explanation:"ZTA uses identity, posture, and metadata when payloads are opaque; disabling encryption or implicit trust violates ZTA." },
  { id:60420, domain:2, level:1, question:"Which statement about the seven tenets and resources is correct?", options:["Only databases are treated as resources, while applications and services are excluded entirely","Resources are limited strictly to the physical hardware located in the enterprise data center","All data sources and computing services are treated as resources to be protected under policy","Resources include only the assets that are owned and operated directly by the enterprise itself"], correct:2, explanation:"Tenet one defines all data sources and computing services as resources; the scope is broad, not limited to databases or hardware." },
  { id:60421, domain:2, level:2, question:"Which describes the policy engine's behavior when its inputs indicate elevated risk?", options:["It always grants access but logs the risk for an administrator to review at a later time here","It ignores the risk signals because identity authentication alone determines the final outcome","It may deny access or require additional verification based on the elevated risk signals seen","It permanently blocks the subject from all enterprise resources until a manual reset is done"], correct:2, explanation:"Elevated risk may lead the PE to deny or step up verification; it does not blindly grant nor permanently block by default." },
  { id:60422, domain:2, level:2, question:"What does it mean that ZTA shifts defenses from the perimeter to the resource?", options:["The perimeter firewall becomes the only enforcement point for every resource in the network","All resources are relocated physically to a single hardened data center for centralized defense","Protection and policy enforcement are applied close to each resource rather than at one boundary","The enterprise no longer needs to authenticate any subjects because resources defend themselves"], correct:2, explanation:"ZTA enforces policy near each resource instead of at one perimeter; it does not relocate resources or drop authentication." },
  { id:60423, domain:2, level:3, question:"A ZTA assumes the enterprise may not own the entire infrastructure path. What design implication follows?", options:["The enterprise must encrypt and authenticate communications even over infrastructure it does not own","The enterprise should avoid any use of cloud services since it cannot control the underlying network","The enterprise can trust third-party networks fully because they fall outside its security scope here","The enterprise must place all resources on premises to maintain control over the entire network path"], correct:0, explanation:"Since the path may not be enterprise-owned, communications must still be encrypted and authenticated; avoiding cloud is not required." },
  { id:60424, domain:2, level:1, question:"In the CISA model, what are the four maturity stages an organization progresses through?", options:["Traditional, initial, advanced, and optimal, representing increasing Zero Trust maturity levels","Bronze, silver, gold, and platinum, representing increasing certification achievement tiers earned","Plan, build, run, and retire, representing the standard lifecycle phases of any IT system here","Crawl, walk, jog, and run, representing an informal description of the adoption speed chosen now"], correct:0, explanation:"CISA's stages are Traditional, Initial, Advanced, and Optimal; the other sets are not the official maturity stages." },
  { id:60425, domain:2, level:2, question:"How should an organization interpret the cross-cutting capabilities in the CISA model?", options:["As optional add-ons that only apply once an organization reaches the optimal maturity stage","As a replacement for the five pillars that makes the individual pillar assessments unnecessary","As capabilities that span and support all five pillars rather than belonging to just one pillar","As physical security controls that operate independently of the digital Zero Trust pillars here"], correct:2, explanation:"Cross-cutting capabilities like visibility, automation, and governance support all five pillars rather than standing alone." },
  { id:60426, domain:2, level:3, question:"Why does the DoD reference architecture emphasize data-centric security within Zero Trust?", options:["Because protecting the network perimeter is sufficient once strong firewalls are in place fully","Because the data plane should carry the access decisions instead of the actual application traffic","Because data-centric security removes the need for any identity or device controls in the design","Because data is the ultimate target, so controls should follow and protect the data itself directly"], correct:3, explanation:"Data-centric security protects the ultimate target wherever it resides; perimeter focus and dropping identity controls run counter to it." },
  { id:60427, domain:2, level:1, question:"Which component is best described as the brain of the Zero Trust decision process?", options:["The policy enforcement point that physically permits or blocks the connection to a resource","The identity provider that stores the authoritative records of all the enterprise subjects here","The policy engine that applies the trust algorithm to render the access decision for a request","The continuous diagnostics system that reports device posture into the decision-making process"], correct:2, explanation:"The PE is the decision brain applying the trust algorithm; the PEP enforces and the IdP and CDM are input sources." },
  { id:60428, domain:2, level:2, question:"What happens to access in a ZTA when the policy administrator instructs session teardown?", options:["The subject retains access until the session naturally times out at the end of the workday","The policy engine re-grants the access automatically because the subject was already trusted","The enforcement point closes the connection, ending the subject's access to that resource","The identity provider issues a new credential so the subject can immediately reconnect again"], correct:2, explanation:"On a teardown instruction the PEP closes the connection and ends access; trust does not silently persist or auto-renew." },
  { id:60429, domain:2, level:3, question:"An auditor asks how a ZTA ensures access is not granted based on network location. Which design feature answers this?", options:["The enterprise relies on VLAN tags to confirm that a device is within the trusted network zone","The policy engine evaluates identity, posture, and context rather than where the request originates","The perimeter firewall classifies any internal source address as automatically trusted by default","The enforcement point grants access to any device whose IP falls within the corporate range here"], correct:1, explanation:"The PE decides on identity, posture, and context, not location; VLAN, perimeter, and IP-range trust are what ZTA rejects." },
  { id:60430, domain:2, level:1, question:"Which is a recognized data source that the policy engine may draw upon for decisions?", options:["The session payload itself, which the engine decrypts and reads to authorize each request now","The physical building access turnstiles that record when employees enter the office floors here","The activity logs that capture the historical behavior of subjects and assets over a long time","The corporate travel booking system that records where employees are traveling each week now"], correct:2, explanation:"Activity logs are a recognized PE data source; reading payloads, turnstiles, and travel systems are not 800-207 inputs." },
  { id:60431, domain:2, level:2, question:"Why does ZTA require authentication and authorization for each resource access rather than once?", options:["Because authenticating once at the perimeter is faster and reduces the load on the directory","Because resources are unable to share a common identity provider across the whole enterprise","Because trust must be established per resource to prevent broad access from a single grant","Because the data plane needs a fresh credential to be able to carry each individual packet now"], correct:2, explanation:"Per-resource authn and authz prevents one grant from yielding broad access; it is about least privilege, not perimeter speed." },
  { id:60432, domain:2, level:2, question:"Which describes how the enclave model handles enforcement compared to the device agent model?", options:["The enclave model places a gateway in front of a group of resources rather than each resource","The enclave model requires a software agent installed on every backend resource in the group","The enclave model eliminates the enforcement point entirely for the resources inside the group","The enclave model decides access using the resource itself instead of any policy decision point"], correct:0, explanation:"The enclave model fronts a group of resources with one gateway; it still uses a PDP and does not require per-resource agents." },
  { id:60433, domain:2, level:3, question:"A security team wants to limit the blast radius if one PEP is compromised. Which ZTA practice helps?", options:["Centralizing all enforcement into one large PEP at the network perimeter for simpler control","Granting every authenticated subject standing access to reduce the number of PEPs needed now","Removing the policy decision point so each resource can decide access entirely on its own here","Distributing enforcement across many PEPs so a single compromise affects only its own scope"], correct:3, explanation:"Distributing PEPs limits the impact of any single compromise; centralizing or removing components increases risk." },
  { id:60434, domain:2, level:1, question:"What is the relationship between the data plane and the policy enforcement point?", options:["The PEP operates on the data plane to enforce decisions on the actual subject-to-resource traffic","The PEP operates only on the control plane and never touches any of the application traffic at all","The PEP and the data plane are the same component described using two interchangeable names","The PEP exists solely to compute trust scores and has no role in the data plane connection here"], correct:0, explanation:"The PEP enforces decisions on data-plane traffic; it is informed by the control plane but acts on the actual connection." },
  { id:60435, domain:2, level:2, question:"How does the trust algorithm typically treat a request from a newly enrolled, unverified device?", options:["It grants full access immediately because enrollment alone establishes complete device trust","It ignores the device entirely and bases the decision only on the subject's username provided","It applies stricter scrutiny or limited access until sufficient confidence in the device is built","It permanently blacklists the device because new devices are assumed to be malicious by default"], correct:2, explanation:"Low confidence in a new device leads to stricter scrutiny or limited access; it neither auto-grants nor blacklists outright." },
  { id:60436, domain:2, level:2, question:"Which statement correctly contrasts the control plane and the data plane in a ZTA?", options:["The control plane makes and conveys decisions while the data plane carries the authorized traffic","The control plane carries the bulk traffic while the data plane only handles the policy decisions","Both planes perform identical functions and exist only to provide redundancy for one another here","The data plane authenticates the subjects while the control plane encrypts the resource payloads"], correct:0, explanation:"The control plane handles decisions and signaling; the data plane carries authorized traffic, with distinct roles each." },
  { id:60437, domain:2, level:3, question:"An organization's PDP and PEP rely on a closed vendor protocol that cannot integrate with new tools. Which ZTA threat applies?", options:["A denial-of-service threat that exhausts the decision capacity of the policy decision point here","A network-visibility threat caused by pervasive encryption hiding the malicious activity flows","A stolen-credential threat that lets attackers impersonate legitimate authenticated subjects now","The reliance on proprietary data formats, creating lock-in and limiting interoperability options"], correct:3, explanation:"A closed protocol blocking integration is the proprietary-format and interoperability threat; the others are distinct risks." },
  { id:60438, domain:2, level:1, question:"Which best describes the ZTA tenet regarding device security posture?", options:["The enterprise measures and maintains the security posture of all assets it owns and uses","The enterprise checks posture once at procurement and then trusts the device for its lifetime","The enterprise relies on each user to self-attest that their personal device is secure enough","The enterprise ignores posture because identity verification alone determines all of the access"], correct:0, explanation:"The tenet calls for continuously measuring and maintaining asset posture; one-time checks and self-attestation are insufficient." },
  { id:60439, domain:2, level:2, question:"In a ZTA, what is the most accurate statement about implicit trust zones?", options:["They are expanded as much as possible so that internal communication remains fast and simple","They are defined by physical location so that office devices are trusted more than remote ones","They are required around every resource so that internal subjects can move freely between assets","They are minimized so that access requires explicit policy evaluation rather than assumed trust"], correct:3, explanation:"ZTA minimizes implicit trust zones, forcing explicit per-request evaluation; expanding or location-based zones contradict it." },
  { id:60440, domain:2, level:3, question:"Why might an enterprise feed both CDM data and threat intelligence into its policy engine?", options:["To remove the requirement for the enforcement point to mediate any of the resource connections","To allow the policy engine to carry the application traffic on the control plane during outages now","To permanently trust any asset whose posture and the threat feed both happen to look clean once","To combine internal asset posture with external threat context for more informed access decisions"], correct:3, explanation:"Combining internal posture and external threat context yields richer decisions; it does not bypass the PEP or grant lasting trust." },
  { id:60441, domain:2, level:1, question:"Which logical component would an administrator configure to define who can access a resource?", options:["The data access policy that the policy engine consults when it evaluates each access request","The data plane channel that carries the authorized application traffic toward the resource","The continuous diagnostics agent that reports the endpoint posture into the decision process","The session token that the subject presents to the resource at the moment of connection now"], correct:0, explanation:"Administrators define authorization in the data access policy used by the PE; the others are not where access rules are set." },
  { id:60442, domain:2, level:2, question:"What is the consequence if a ZTA lacks reliable identity management?", options:["Access decisions become unreliable because the policy engine cannot trust the subject attributes","Access becomes faster because the policy engine no longer needs to evaluate any identity data here","The enforcement point can no longer carry application traffic between subjects and resources now","The control plane and the data plane automatically merge into one combined communication path"], correct:0, explanation:"Without reliable identity, the PE cannot trust subject attributes, undermining decisions; it does not affect planes or traffic flow." },
  { id:60443, domain:2, level:3, question:"An enterprise wants resilient access if one policy decision point instance fails. Which approach aligns with ZTA availability concerns?", options:["Deploy a single hardened PDP and accept that an outage will halt all enterprise access entirely","Deploy redundant PDP instances so decisions can continue if one instance becomes unavailable","Remove the PDP and let each resource make its own independent access decisions in isolation here","Grant standing access to all subjects in advance so the PDP is never queried during an outage now"], correct:1, explanation:"Redundant PDP instances address the DoS and availability threat; removing the PDP or granting standing access weakens ZTA." },
  { id:60444, domain:2, level:1, question:"Which best describes a policy enforcement point in relation to the control plane?", options:["The PEP receives instructions from the control plane and enforces them on actual connections","The PEP issues the access decisions and the control plane merely logs them after the fact here","The PEP and the control plane never communicate, operating in complete isolation from each other","The PEP defines the data access policy that the control plane distributes to all the resources"], correct:0, explanation:"The PEP receives control-plane instructions and enforces them; it does not decide, work in isolation, or author policy." },
  { id:60445, domain:2, level:2, question:"How does ZTA expect to handle service-to-service (non-person entity) communication?", options:["It exempts NPE communication from policy because automated services are inherently trusted here","It blocks all NPE communication outright since only human subjects may access resources now","It trusts NPE communication as long as both services reside on the same internal subnet here","It applies authentication, authorization, and least privilege to NPE communication as well too"], correct:3, explanation:"NPEs must authenticate and be authorized with least privilege like any subject; they are not exempt or implicitly trusted." },
  { id:60446, domain:2, level:3, question:"A ZTA deployment must protect a SaaS application the enterprise does not host. Which consideration is most relevant?", options:["The enterprise cannot apply any Zero Trust principles because it does not own the SaaS servers","All Zero Trust enforcement is delegated entirely to the SaaS provider with no enterprise role here","The SaaS must be relocated on premises before any Zero Trust controls can be applied to it now","Access can still be mediated through identity, policy, and enforcement integrated with the SaaS"], correct:3, explanation:"Even unhosted SaaS can be brought under identity, policy, and enforcement integration; ZTA assumes resources may be off-premises." },
  { id:60447, domain:2, level:1, question:"Which describes the purpose of the trust algorithm's multiple inputs?", options:["To slow down the decision process so that administrators have time to manually review requests","To provide a richer basis for the access decision than any single factor could provide alone","To ensure that the data plane has enough information to route the traffic to the resource here","To replace the need for any policy enforcement point by deciding and enforcing in one step now"], correct:1, explanation:"Multiple inputs give the trust algorithm a richer decision basis; they do not slow review, route traffic, or replace the PEP." },
  { id:60448, domain:2, level:2, question:"Which is the most accurate description of the policy engine and policy administrator interaction?", options:["The PE makes a decision and the PA acts on that decision to configure the enforcement point","The PA makes the decision and the PE simply records it in the central activity log afterward","Both the PE and the PA independently make competing decisions that are later reconciled here","The PE and the PA both physically open the connection from the subject to the resource now"], correct:0, explanation:"The PE decides and the PA executes by configuring the PEP; they do not compete or both open connections." },
  { id:60449, domain:2, level:3, question:"Why is visibility into non-person entity activity important for ZTA security?", options:["Because non-person entities never require monitoring once they have been initially configured","Because monitoring non-person entities removes the need to monitor any of the human subjects","Because non-person entities operate exclusively on the control plane and are therefore irrelevant","Because compromised automation can abuse standing privileges, so its activity must be observed"], correct:3, explanation:"Compromised NPEs can abuse privileges, so monitoring their activity is essential; they are not exempt from observation." },
  { id:60450, domain:2, level:1, question:"What does NIST SP 800-207 identify as the focus of protection in a ZTA?", options:["The network perimeter, which is hardened to keep all of the external attackers fully outside","The resources, including the data, applications, and services, that must be protected by policy","The physical office buildings, where access is controlled by badges and security personnel here","The endpoint antivirus software, which is the primary control preventing any compromise now"], correct:1, explanation:"ZTA focuses protection on resources such as data, applications, and services; it does not center on the perimeter or buildings." },
  { id:60451, domain:2, level:2, question:"How does a ZTA treat a previously trusted session if new threat intelligence flags the subject?", options:["It leaves the session untouched because trust was already established at the start of the session","It automatically extends the session duration to give the subject more time to finish the task","It can re-evaluate and revoke the session in response to the new threat intelligence received","It permanently deletes the subject's account from the directory the moment any flag is raised"], correct:2, explanation:"New threat intel can trigger re-evaluation and revocation mid-session; ZTA does not leave sessions untouched or auto-delete accounts." },
  { id:60452, domain:2, level:2, question:"Which is a correct statement about the policy enforcement point's placement options?", options:["A PEP can be a local agent, a gateway, or a portal depending on the deployment model chosen","A PEP must always be a physical hardware appliance installed in the enterprise data center here","A PEP can only ever be located at the single internet-facing perimeter of the whole network now","A PEP must be embedded inside the policy engine to keep enforcement and decisions together now"], correct:0, explanation:"PEPs can take various forms (agent, gateway, portal) per the deployment model; they are not limited to one hardware perimeter form." },
  { id:60453, domain:2, level:3, question:"An enterprise's trust algorithm only checks a fixed list of attributes and never weighs behavior. Which type and limitation applies?", options:["It is contextual and its limitation is that it cannot incorporate any static subject attributes","It is score-based and its limitation is that it can never reach a definitive access decision here","It is perimeter-based and its limitation is that it relies entirely on encryption for its security","It is criteria-based and its limitation is that it cannot adapt to dynamic behavioral context now"], correct:3, explanation:"A fixed-attribute check is criteria-based and lacks dynamic behavioral context, which the score-based contextual variant provides." },
  { id:60454, domain:2, level:1, question:"Which statement about ZTA and encryption is most accurate?", options:["Encryption must be disabled so the enforcement point can inspect every packet for any threats","Encryption applies only to the traffic that crosses the enterprise internet-facing perimeter here","Encryption replaces the need for authentication because encrypted traffic is inherently trusted","Securing communications with encryption supports the tenet that all communication is protected"], correct:3, explanation:"Encryption supports the tenet of securing all communications; ZTA does not disable encryption or limit it to the perimeter." },
  { id:60455, domain:2, level:2, question:"What is the main risk if an enterprise grants implicit trust based on a one-time login?", options:["The session becomes encrypted automatically, which reduces the policy engine's visibility into it","The policy administrator is forced to tear down the session before any traffic can begin to flow","The data plane is unable to carry the authorized traffic until the subject logs in a second time","A compromised session retains access without re-evaluation, enabling extended unauthorized use"], correct:3, explanation:"One-time implicit trust lets a compromised session persist unchecked; per-session re-evaluation is the ZTA mitigation." },
  { id:60456, domain:2, level:3, question:"A ZTA must continue functioning during a partial network outage affecting some PEPs. Which design choice supports this?", options:["Routing all access through a single central PEP so failures are easier to detect and fix quickly","Granting standing access to every subject in advance so PEP availability no longer matters at all","Removing PEPs from the design so that resources are reachable directly during the outage period","Distributing PEPs near resources so the failure of some does not block access to unaffected ones"], correct:3, explanation:"Distributed PEPs localize outages so unaffected resources stay reachable; centralizing or removing PEPs harms resilience." },
  { id:60457, domain:2, level:1, question:"Which describes the policy engine's role most precisely?", options:["It is the component that ultimately decides whether to grant access using the trust algorithm","It is the component that physically enforces the decision by gating the resource connection here","It is the directory that stores all of the enterprise subject identities and their attributes now","It is the feed that supplies external threat intelligence into the access decision process here"], correct:0, explanation:"The PE decides using the trust algorithm; enforcement, identity storage, and threat feeds are separate components or sources." },
  { id:60458, domain:2, level:2, question:"Why does ZTA consider the local network connection of a remote subject untrusted?", options:["Because remote connections are always slower and therefore unsuitable for sensitive access","Because remote subjects are inherently malicious and should never be granted any access at all","Because the enterprise does not control that network and it could be observed or manipulated","Because the data plane cannot encrypt traffic that originates from outside the enterprise network"], correct:2, explanation:"The enterprise does not control a remote local network, so it may be observed or tampered with; thus it is treated as untrusted." },
  { id:60459, domain:2, level:3, question:"An organization maps its controls to the CISA pillars and finds gaps in automation and orchestration. What does this indicate?", options:["A gap in a core pillar that fully blocks any progress on the five primary pillars themselves here","A gap that only matters once the organization has already reached the optimal maturity stage now","A gap in a cross-cutting capability that affects maturity across all five of the pillars broadly","A gap that is irrelevant because automation is outside the scope of the CISA maturity model here"], correct:2, explanation:"Automation and orchestration is a cross-cutting capability whose gaps affect maturity across all pillars, not a single pillar." },
  { id:60460, domain:2, level:1, question:"In a ZTA, which entity presents credentials when requesting access to a resource?", options:["The subject, which may be a user, an application, or a non-person automated entity in the system","The policy enforcement point, which authenticates itself to the resource on the subject's behalf","The policy engine, which provides its own credentials to authorize the access being requested","The continuous diagnostics system, which authenticates so it can report the device posture data"], correct:0, explanation:"The subject presents credentials when requesting access; the PEP, PE, and CDM serve enforcement, decision, and posture roles." },
  { id:60461, domain:2, level:2, question:"How does the policy administrator relate to the policy engine in the decision workflow?", options:["The PA evaluates the trust algorithm while the PE simply records the outcome for later auditing","The PA and the PE both authenticate the subject before the access request can be considered now","The PA executes the decision the PE makes by configuring the enforcement point appropriately","The PA defines the data access policy that the PE then distributes out to every resource gateway"], correct:2, explanation:"The PA executes the PE's decision by configuring the PEP; it does not evaluate the algorithm, authenticate, or author policy." },
  { id:60462, domain:2, level:3, question:"A red team subverts the policy administrator and issues fraudulent session commands. What is the impact?", options:["No impact occurs because the policy engine independently re-verifies every command the PA sends","The data plane stops carrying any traffic because the PA controls all of the application flows now","Attackers can cause the enforcement point to open unauthorized sessions to protected resources","The trust algorithm automatically reverts to criteria-based mode to compensate for the breach here"], correct:2, explanation:"A subverted PA can command the PEP to open unauthorized sessions, a serious threat; the PE does not independently re-verify each command." },
  { id:60463, domain:2, level:1, question:"Which best states the relationship between the seven tenets and an actual ZTA implementation?", options:["The tenets are abstract goals that real implementations approach using various architectures","The tenets are strict product requirements that only one specific vendor's tool can satisfy here","The tenets describe physical security controls for the data center rather than network access now","The tenets replace the need for a policy decision point by listing fixed allow-and-deny rules here"], correct:0, explanation:"The tenets are guiding goals realized through varied architectures; they are not single-vendor requirements or physical controls." },
  { id:60464, domain:2, level:2, question:"Which scenario shows correct application of the dynamic policy tenet?", options:["Granting access based only on the static department field stored in the identity directory record","Granting access to any device whose IP address falls inside the corporate network address range","Adjusting an access decision based on real-time device posture, location risk, and behavior signals","Allowing access for the whole day once the subject authenticates successfully in the morning here"], correct:2, explanation:"Dynamic policy adjusts decisions using real-time signals; static fields, IP ranges, and all-day grants are not dynamic policy." },
  { id:60465, domain:2, level:3, question:"An enterprise must show that compromising one resource does not yield access to others. Which ZTA characteristic demonstrates this?", options:["Per-session, per-resource access ensures a grant to one resource does not extend to other resources","A flat trusted internal network ensures that all resources are reachable once a device is inside here","One-time authentication ensures the subject does not have to re-prove its identity for other assets","Implicit trust by subnet ensures fast access between resources hosted in the same network segment"], correct:0, explanation:"Per-session, per-resource access confines a grant to one resource; flat networks and implicit subnet trust enable cross-access." },
  { id:60466, domain:2, level:1, question:"What is the purpose of the policy enforcement point monitoring an active connection?", options:["To compute the trust score that determines whether the connection should have been allowed here","To store the subject's identity attributes for the identity provider to reference during login now","To support continuous evaluation and enable termination if the session conditions change later","To author the data access policy that governs which subjects may reach which resources here"], correct:2, explanation:"PEP monitoring supports continuous evaluation and enables session termination; scoring, identity storage, and policy authoring are other roles." },
  { id:60467, domain:2, level:2, question:"Which statement correctly describes the data access policy as a policy engine input?", options:["It is the set of rules defining authorization that the policy engine applies to each request received","It is the live application traffic that the engine inspects to authorize each individual data packet","It is the certificate authority that signs the credentials the subjects present during their login","It is the diagnostic agent that reports the endpoint posture into the access decision process here"], correct:0, explanation:"The data access policy provides authorization rules to the PE; it is not traffic, a certificate authority, or a diagnostic agent." },
  { id:60468, domain:2, level:3, question:"An organization wants its ZTA to detect when a valid user behaves abnormally and tighten access. Which input enables this?", options:["The static PKI certificate, which confirms identity but reveals nothing about the user's behavior","The data access policy, which lists fixed rules but does not track real-time behavior of the user","Activity logs and SIEM analytics, which surface behavioral anomalies for the policy engine to weigh","The deployment model choice, which determines enforcement placement but not behavioral analysis"], correct:2, explanation:"Activity logs and SIEM analytics surface behavioral anomalies the PE can act on; certificates and static policy do not track behavior." },
  { id:60469, domain:2, level:1, question:"Which is a correct pairing of a ZTA threat with its description?", options:["Stolen credentials: an attacker presents valid credentials to satisfy policy and gain access","Proprietary formats: an attacker overwhelms the policy decision point with excessive requests","Denial of service: an attacker hides malicious activity within encrypted east-west traffic flows","Network visibility: an attacker locks the enterprise into a single vendor's closed data format"], correct:0, explanation:"Stolen credentials let an attacker satisfy policy; the other descriptions are mismatched to the wrong threat names." },
  { id:60470, domain:2, level:2, question:"Why does NIST recommend that ZTA components support open standards and formats?", options:["Because open standards make encryption unnecessary for the communication between components","Because open standards remove the need for any policy decision point in the architecture entirely","Because open standards guarantee that the policy engine can never be subject to denial of service","Because interoperability reduces lock-in risk and lets components from different vendors integrate"], correct:3, explanation:"Open standards support interoperability and reduce lock-in; they do not remove encryption needs, the PDP, or DoS risk." },
  { id:60471, domain:2, level:3, question:"A ZTA design routes all subject requests through a PEP that cannot read encrypted payloads. How can policy still be enforced?", options:["By decrypting every payload at the PEP so the engine has full visibility into the request content","By trusting all encrypted requests automatically since the encryption already protects the data fully","By removing the PEP so that the encrypted requests can reach the resource without any inspection","By using identity, device posture, and connection metadata as the basis for the access decision"], correct:3, explanation:"Policy can rely on identity, posture, and metadata when payloads are opaque; auto-trusting encryption or removing the PEP violates ZTA." },
  { id:60472, domain:2, level:1, question:"Which statement about the DoD and CISA Zero Trust frameworks is accurate?", options:["Both frameworks reject NIST and define entirely independent and incompatible Zero Trust models","Both define exactly the same five pillars and use identical maturity stage naming conventions","Both apply only to physical access control and do not address network or identity-based access","Both operationalize Zero Trust principles, using pillars to guide adoption within their domains"], correct:3, explanation:"Both frameworks operationalize Zero Trust via pillars; they align with NIST principles but differ in pillar counts and details." },
  { id:60473, domain:2, level:2, question:"How should the relationship between the PEP and the resource be characterized in terms of trust?", options:["The PEP trusts the resource implicitly and forwards any request without applying the policy","The resource trusts any traffic the PEP forwards and skips its own authentication step entirely","The PEP and the resource share a single credential so that neither needs to authenticate anew","The PEP enforces policy on every request so the resource never receives unmediated access"], correct:3, explanation:"The PEP enforces policy so the resource only sees mediated access; it does not blindly forward or share credentials." },
  { id:60474, domain:2, level:3, question:"An enterprise discovers attackers gained network visibility by sniffing unencrypted internal traffic. Which ZTA tenet addresses this gap?", options:["The tenet that all data sources and computing services are to be treated as protectable resources","The tenet that access is granted strictly on a per-session basis with continuous re-evaluation","The tenet that the enterprise continuously monitors and measures the integrity of all of its assets","The tenet that all communication is secured regardless of the network location it traverses now"], correct:3, explanation:"Securing all communication regardless of location directly addresses unencrypted internal traffic sniffing; the others target different concerns." },
  { id:60475, domain:2, level:1, question:"What role does the continuous diagnostics and mitigation system play in a ZTA?", options:["It physically enforces the decision by opening or closing the connection to the resource itself","It stores the authoritative identity records for all of the subjects across the entire enterprise","It carries the authorized application traffic along the data plane to the protected resource now","It supplies current information about the state and security posture of assets to the policy engine"], correct:3, explanation:"CDM supplies real-time asset state and posture to the PE; enforcement, identity storage, and traffic are other components' roles." },
  { id:60476, domain:2, level:2, question:"Which describes a correct ZTA response when continuous monitoring detects a session anomaly?", options:["The system ignores the anomaly because the subject already authenticated at session start here","The system grants the subject elevated privileges to finish the task before any investigation","The system permanently disables the resource so no subject can ever access it again afterward","The system can re-evaluate trust and instruct the PEP to restrict or terminate the session now"], correct:3, explanation:"On detecting an anomaly, ZTA re-evaluates and can restrict or end the session; it does not ignore anomalies or grant elevation." },
  { id:60477, domain:2, level:3, question:"Why is it risky to rely on a single policy decision point instance in a production ZTA?", options:["Because a single PDP cannot evaluate more than one trust algorithm criterion at any given time","Because a single PDP is unable to communicate with more than one enforcement point at once","Because a single PDP forces all of the application traffic to traverse the control plane directly","Because a single PDP is a single point of failure vulnerable to denial-of-service disruption"], correct:3, explanation:"A single PDP is a single point of failure and DoS target; redundancy addresses this availability threat in production." },
  { id:60478, domain:2, level:1, question:"Which best describes how access is established once the policy engine approves a request?", options:["The subject connects to the resource directly and the policy engine logs it after completion","The policy administrator configures the enforcement point to establish the approved session path","The continuous diagnostics system opens the connection after confirming the device posture data","The identity provider issues a new certificate and forwards the traffic to the resource itself"], correct:1, explanation:"After approval the PA configures the PEP to establish the session; the subject does not connect directly nor does CDM open it." },
  { id:60479, domain:2, level:2, question:"Which statement reflects the assumption that the enterprise may not own the full communication path?", options:["The enterprise must therefore avoid all cloud and third-party services to retain full control","The enterprise can fully trust any third-party network because responsibility shifts to that party","The enterprise must place all of its resources on premises to guarantee path-level control fully","The enterprise must secure and authenticate communications even across networks it does not own"], correct:3, explanation:"Since the path may not be owned, communications must be secured and authenticated regardless; avoiding cloud is not the implication." },
  { id:60480, domain:2, level:3, question:"An enterprise wants to apply Zero Trust to legacy systems that cannot run modern agents. Which deployment fits best?", options:["The device agent and gateway model, which requires installing a modern agent on each legacy host","The enclave or portal model, which places enforcement in front of the legacy systems instead now","A flat trusted network model, which grants the legacy systems unrestricted internal access freely","The device application sandboxing model, which depends on the legacy hosts running vetted apps"], correct:1, explanation:"Enclave or portal models front legacy systems with external enforcement, avoiding agent requirements those systems cannot meet." },
  { id:60481, domain:2, level:1, question:"What is the primary distinction between the policy engine and the policy enforcement point?", options:["The policy engine decides on access while the policy enforcement point applies that decision","The policy engine applies decisions while the policy enforcement point computes the trust scores","The policy engine stores the identities while the policy enforcement point authors the access policy","The policy engine carries the traffic while the policy enforcement point logs each completed session"], correct:0, explanation:"The PE decides and the PEP enforces; the distractors swap or misassign their responsibilities entirely." },
  { id:60482, domain:2, level:2, question:"How does ZTA's per-session model affect a subject moving from one resource to another?", options:["The subject reuses the same grant since access to one resource covers all the related resources","The subject is automatically denied because moving between resources is treated as suspicious here","The subject's session is permanently terminated and the account is locked until an admin resets it","The subject must satisfy policy again for the new resource rather than reuse the prior access grant"], correct:3, explanation:"Per-session, per-resource access requires fresh policy satisfaction for each resource; prior grants do not transfer across resources." },
  { id:60483, domain:2, level:3, question:"A trust algorithm receives conflicting signals: valid credentials but a device failing posture checks. How should a contextual algorithm respond?", options:["Grant access because valid credentials always outweigh any concerns raised by device posture","Ignore the posture signal entirely since the trust algorithm should only consider the identity factor","Permanently revoke the subject's credentials because the device failed a single posture check here","Weigh both signals together and likely deny or restrict access due to the elevated overall risk now"], correct:3, explanation:"A contextual algorithm weighs all signals and may deny or restrict given the risk; credentials alone do not override posture concerns." },
  { id:60484, domain:2, level:1, question:"Which of the following is a logical data source feeding the policy engine in NIST SP 800-207?", options:["The data plane channel, which transports the authorized traffic toward the protected resource","The industry compliance requirements that the organization is subject to under its regulations","The session establishment command that the policy administrator sends to the enforcement point","The host posture reported by the continuous diagnostics and mitigation system to the engine"], correct:3, explanation:"CDM host posture is a recognized PE data source; the data plane, compliance rules, and PA commands are not listed PE inputs." },
  { id:60485, domain:2, level:2, question:"Which is the best description of how a ZTA uses threat intelligence?", options:["It uses threat intelligence to enforce the connection in place of the policy enforcement point","It relies on threat intelligence to store the identities of all of the subjects in the enterprise","It uses threat intelligence to carry the authorized application traffic across the data plane fully","It incorporates external threat indicators into the policy engine to inform the access decisions"], correct:3, explanation:"Threat intelligence informs PE decisions as an input; it does not enforce connections, store identities, or carry traffic." },
  { id:60486, domain:2, level:3, question:"An enterprise aligns its program to the CISA optimal stage but still uses manual approvals for some access. What does this reveal?", options:["The program already meets the optimal stage because some automation has been introduced already","Nothing meaningful, because manual approvals are explicitly required at every CISA maturity stage","That the program should drop back to the traditional stage and restart the entire adoption effort","A gap, since the optimal stage expects fully automated and dynamic policy rather than manual steps"], correct:3, explanation:"The optimal stage expects fully automated dynamic policy, so remaining manual approvals indicate a maturity gap, not optimal status." },
  { id:60487, domain:2, level:1, question:"Which component would be configured to terminate an active session in a ZTA?", options:["The policy enforcement point, acting on instruction from the policy administrator to close it","The identity provider, which revokes the subject's stored credentials to end the active session","The continuous diagnostics system, which stops reporting posture so the session naturally lapses","The data access policy store, which deletes the relevant rule to cut off the subject's access now"], correct:0, explanation:"The PEP terminates the session when instructed by the PA; revoking credentials, halting posture, or deleting rules are not the mechanism." },
  { id:60488, domain:2, level:2, question:"Why is the separation of the control plane and data plane important for ZTA security?", options:["It ensures the application traffic and the decision-making traffic do not depend on each other","It guarantees that the policy engine never needs to evaluate any of the incoming access requests","It allows the enterprise to disable encryption on the data plane while keeping the control plane safe","It removes the need for any policy enforcement point because the planes enforce themselves directly"], correct:0, explanation:"Plane separation decouples decision traffic from application traffic for better security and management; it does not drop the PE, encryption, or PEP." },
  { id:60489, domain:2, level:3, question:"A ZTA must protect against an attacker who steals a session token mid-stream. Which capability most directly helps?", options:["Issuing long-lived tokens so users rarely need to re-authenticate during their normal workday","A flat trusted network that lets the token holder move freely once they are inside the perimeter","Implicit trust for any session that originated from a device on the corporate internal subnet now","Continuous evaluation that can detect anomalies and instruct the PEP to terminate the session now"], correct:3, explanation:"Continuous evaluation can spot anomalous token use and revoke the session; long-lived tokens and implicit trust worsen the risk." },
  { id:60490, domain:2, level:1, question:"Which best describes an enterprise resource in the context of NIST SP 800-207?", options:["Any data source or computing service that the enterprise needs to protect under its access policy","Only the network firewalls and intrusion prevention sensors deployed at the enterprise perimeter","Strictly the user accounts and groups maintained within the central identity directory service here","Exclusively the physical servers and storage arrays located within the on-premises data center now"], correct:0, explanation:"A resource is broadly any data source or computing service requiring protection; it is not limited to firewalls, accounts, or hardware." },
  { id:60491, domain:2, level:2, question:"How does the trust algorithm contribute to enforcing least privilege in a ZTA?", options:["By granting the broadest possible access so the subject never needs to request access again later","By caching prior decisions so the same broad access is reused for every future request that arrives","By ignoring resource sensitivity so all requests are treated identically regardless of the asset here","By evaluating each request so that access is limited to what the current context actually justifies"], correct:3, explanation:"The trust algorithm scopes access to what context justifies, supporting least privilege; broad or cached grants undermine it." },
  { id:60492, domain:2, level:3, question:"An enterprise wants to ensure its ZTA does not collapse if proprietary components are replaced. Which approach reduces this risk?", options:["Standardizing on one vendor's proprietary data formats so every component speaks the same language","Avoiding any logging so there is less proprietary data to migrate when a component is replaced now","Hard-coding the access rules into each resource so the policy engine becomes entirely optional here","Adopting open standards and interfaces so components can be swapped without breaking integration"], correct:3, explanation:"Open standards and interfaces reduce lock-in and ease component replacement; proprietary formats are exactly the risk to avoid." },
  { id:60493, domain:2, level:1, question:"What does the trust algorithm rely on to make a per-request access decision?", options:["A combination of inputs such as identity, posture, resource sensitivity, and threat context","Only the physical port number on the switch into which the requesting device is connected here","Exclusively the time of day and the day of week on which the access request is being made now","Solely a static allowlist of trusted devices that never changes once it has been configured once"], correct:0, explanation:"The trust algorithm combines multiple inputs per request; port, time alone, or a static allowlist are insufficient bases." },
  { id:60494, domain:2, level:2, question:"Which is the most accurate statement about ZTA and the perimeter-based model it replaces?", options:["ZTA keeps the perimeter as the primary control and simply adds encryption on top of it everywhere","ZTA removes all network controls and depends only on the physical security of the data center here","ZTA moves away from implicit perimeter trust toward explicit, per-request verification of access","ZTA trusts everything inside the perimeter while applying strict controls only to external traffic"], correct:2, explanation:"ZTA replaces implicit perimeter trust with explicit per-request verification; it does not retain perimeter trust or drop network controls." },
  { id:60495, domain:2, level:3, question:"A ZTA deployment uses agents on managed devices but must also serve browser-only kiosk users. Which combined design is most appropriate?", options:["Force the kiosk users to install the same device agent that the managed devices already use today","Use the device agent model for managed devices and a resource portal for the browser-only kiosks","Grant the kiosk users standing perimeter VPN access with no further per-request policy checks now","Place all of the users on a single flat trusted network to avoid maintaining two separate models here"], correct:1, explanation:"Agents suit managed devices while an agentless portal serves browser-only kiosks; forcing agents or flat trust breaks the use case." },
  { id:60496, domain:2, level:2, question:"Which statement about the policy administrator and session lifecycle is correct?", options:["The PA only sets up sessions and has no role at all in tearing down any existing session later","The PA decides whether to grant access and then logs the result for the policy engine to review","The PA both establishes and terminates sessions by configuring the enforcement point as needed","The PA carries the authorized traffic between the subject and the resource during the session now"], correct:2, explanation:"The PA both establishes and terminates sessions via the PEP; it does not decide access or carry traffic itself." },
  { id:60497, domain:2, level:3, question:"An enterprise wants its ZTA to remain effective even if an attacker steals credentials and passes initial authentication. Which design principle most helps?", options:["Granting full standing access after authentication so the user experience stays smooth and fast","Trusting the authenticated session entirely since the credentials were validated at the very start","Relying solely on the perimeter firewall to block the attacker before they ever reach a resource","Continuous, contextual evaluation throughout the session to catch anomalous post-authentication behavior"], correct:3, explanation:"Continuous contextual evaluation can detect anomalous behavior after a credential-based login; standing trust and perimeter reliance do not." },
  { id:60498, domain:2, level:1, question:"Which of the following correctly states a ZTA assumption about the network?", options:["The internal network is a trusted zone where devices may communicate freely without restriction","The enterprise-owned network is no more trusted than any non-enterprise network by default here","Devices physically inside the office are trusted more than the devices connecting from remote sites","Threats can only originate externally, so internal traffic requires no inspection or controls now"], correct:1, explanation:"ZTA assumes the enterprise network is not implicitly trusted, on par with external networks; the distractors reflect perimeter assumptions." },
  { id:60499, domain:2, level:2, question:"How does the policy engine use the inputs from its various data sources?", options:["It forwards the inputs unchanged to the resource so the resource can decide on the access itself","It stores the inputs in the data plane so the enforcement point can read them during the session","It encrypts the inputs and sends them to the identity provider for the final access determination","It aggregates and evaluates the inputs through the trust algorithm to reach an access decision now"], correct:3, explanation:"The PE aggregates and evaluates inputs via the trust algorithm to decide; it does not forward decisions to the resource or IdP." },
  { id:60500, domain:2, level:2, question:"Which summary correctly captures the interaction of the core NIST SP 800-207 components?", options:["The PEP decides, the PE enforces, and the PA supplies the identity data used in the decision here","The PA decides, the PEP supplies posture, and the PE carries the authorized application traffic now","The PE decides using the trust algorithm, the PA executes, and the PEP enforces the connection","The identity provider decides, the PE enforces, and the PA carries the traffic to the resource now"], correct:2, explanation:"The PE decides via the trust algorithm, the PA executes the decision, and the PEP enforces the connection; the others misassign roles." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CCZT_C2 = QUESTIONS_CCZT_C2;
